1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty array when given empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill live cells when each has only 1 neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 live neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("should keep a live cell alive when it has 3 live neighbors (survival)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
20	    expect(result).toContainEqual([0, 0]);
21	  });
22	  it("should kill a live cell when it has more than 3 live neighbors (overpopulation)", () => {
23	    const result = nextGeneration([[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]]);
24	    expect(result).not.toContainEqual([1, 1]);
25	  });
26	  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
27	  it.todo("should transform a vertical blinker into a horizontal blinker");
28	  it.todo("should keep a block pattern unchanged (still life)");
29	});
30

1	type Cell = [number, number];
2	
3	const isNeighbor = ([x1, y1]: Cell, [x2, y2]: Cell): boolean =>
4	  (x1 !== x2 || y1 !== y2) &&
5	  Math.abs(x1 - x2) <= 1 &&
6	  Math.abs(y1 - y2) <= 1;
7	
8	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
9	  liveCells.filter((other) => isNeighbor(cell, other)).length;
10	
11	const survives = (neighborCount: number): boolean =>
12	  neighborCount === 2 || neighborCount === 3;
13	
14	export const nextGeneration = (liveCells: Cell[]): Cell[] =>
15	  liveCells.filter((cell) => survives(countLiveNeighbors(cell, liveCells)));
